        .header-explore-btn {
            display: flex;
            align-items: center;
            gap: 6px;
            padding: 8px 14px;
            border-radius: 12px;
            background: var(--accent-secondary);
            color: var(--accent-primary);
            font-size: 0.75rem;
            font-weight: 800;
            border: 1.5px solid var(--border-color);
