        .empty-state { text-align: center; padding: 4rem 2rem; color: var(--text-muted); }
        .empty-state .icon { font-size: 3.5rem; margin-bottom: 1rem; opacity: 0.5; }
        .empty-state p { font-size: 1rem; font-weight: 500; }
      `}</style>
    </div>
  );
};

