            )
        ) : (
            filteredAndSortedList.length === 0 ? (
                <div className="empty-state">
                    <div className="icon">{activeTab === 'all' ? '📚' : '❤️'}</div>
                    <p>{filter === 'all' ? 'Your library is empty.' : 'No matches found.'}</p>
                </div>
            ) : (
                filteredAndSortedList.map(word => {
                    const item = srsData[word];
                    const cache = cardCache[word];
                    const isFaved = favoriteWords.includes(word);
                    const isSelected = selectedWords.has(word);
                    const mastery = item?.masteryLevel || 0;
                    return (
                        <div 
                          key={word} 
                          className={`modern-word-card ${isSelected ? 'selected' : ''}`}
                          onClick={() => handleItemClick(word)}
                          onPointerDown={(e) => startLongPress(word, e)}
                          onPointerUp={cancelLongPress}
                          onPointerLeave={cancelLongPress}
                        >
                            <div className="card-info">
                                <div className="card-top-row">
                                    <span className="word-title">{word}</span>
                                    <div className="card-indicators">
                                        {isFaved && <span className="fav-indicator">❤️</span>}
                                        <button className="row-edit-btn" onClick={(e) => handleOpenEdit(e, word)}>
                                          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"></path><path d="M18.5 2.5a2.121 2.121 0 1 1 3 3L12 15l-4 1 1-4 9.5-9.5z"></path></svg>
                                        </button>
                                    </div>
                                </div>
                                <p className="word-snippet">{cache ? cache.definition : 'AI details loading...'}</p>
                                <div className="mastery-progress-bar">
                                    {[1, 2, 3, 4, 5].map(step => (
                                        <div key={step} className={`progress-dot ${mastery >= step ? 'filled' : ''}`} />
                                    ))}
                                </div>
                            </div>
                            <div className="arrow-icon">
                                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="9 18 15 12 9 6"></polyline></svg>
                            </div>
                        </div>
                    );
                })
            )
        )}
      </div>

      {selectedFamily && (
          <div className="auth-overlay" onClick={() => setSelectedFamily(null)}>
              <div className="family-modal" onClick={e => e.stopPropagation()}>
                  <div className="modal-header">
                      <div className="header-text">🌳 <span>Family Details</span></div>
                      <button className="close-x-btn" onClick={() => setSelectedFamily(null)}>
                        <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                      </button>
                  </div>
                  <div className="modal-scroll-area">
                      <div className="family-member-list">
                          {selectedFamily.allMembers.map(m => {
                              const cap = capitalize(m.word);
                              const isSaved = savedWords.includes(cap);
                              const cache = cardCache[cap];
                              return (
                                  <div key={m.word} className={`member-row ${isSaved ? 'is-saved' : ''}`} onClick={() => onNavigate(cap, true)}>
                                      <div className="member-main">
                                          <div className="member-name-row">
                                              <span className="member-name">{cap}</span>
                                              {m.pos && <span className="member-pos">({m.pos})</span>}
                                              {isSaved && <span className="member-saved-badge">LIBRARY</span>}
                                          </div>
                                          {isSaved && <p className="member-def">{cache?.definition || 'View details...'}</p>}
                                      </div>
                                      <div className="member-arrow"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="9 18 15 12 9 6"></polyline></svg></div>
                                  </div>
                              );
                          })}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {editingWord && <EditWordModal word={editingWord} initialData={cardCache[editingWord]} onClose={() => setEditingWord(null)} onSave={onUpdateWordData} />}

      <style>{`
        .list-tabs-container { display: flex; align-items: center; gap: 12px; margin-bottom: 1.2rem; padding: 0 4px; }
        .list-tabs { flex: 1; display: flex; gap: 6px; background: var(--accent-secondary); padding: 5px; border-radius: 16px; }
        .list-tabs button { flex: 1; padding: 12px; border-radius: 12px; font-size: 0.75rem; font-weight: 800; color: var(--text-secondary); transition: all 0.2s; }
        .list-tabs button.active { background: var(--card-bg); color: var(--accent-primary); }

        .filter-sort-bar { margin: 0 4px 1.5rem 4px; display: flex; flex-direction: column; gap: 14px; }
        .sort-toggles { display: flex; gap: 10px; }
        .sort-toggles button { font-size: 0.65rem; font-weight: 800; padding: 10px 16px; border-radius: 12px; background: var(--card-bg); border: 1px solid var(--border-color); color: var(--text-secondary); }
        .sort-toggles button.active { background: var(--accent-primary); color: white; border-color: var(--accent-primary); }
        .family-view-toggle { display: flex; align-items: center; gap: 6px; background: var(--accent-secondary) !important; color: var(--accent-primary) !important; }
        .family-view-toggle.active { background: var(--accent-primary) !important; color: white !important; }

        .words-scroll-list { display: flex; flex-direction: column; gap: 0.75rem; padding: 0 4px; }
        .modern-word-card { background: var(--card-bg); border-radius: 20px; padding: 1.25rem; display: flex; align-items: center; gap: 1rem; border: 1px solid var(--border-color); cursor: pointer; }
        .modern-word-card.family-card { border-left: 4px solid var(--accent-primary); }
        .family-main-title { display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; font-size: 1rem; line-height: 1.3; }
        .mastery-pill.family-count { background: var(--accent-primary); color: white; padding: 3px 8px; border-radius: 6px; font-size: 0.6rem; font-weight: 800; }

        .card-info { flex: 1; display: flex; flex-direction: column; gap: 4px; overflow: hidden; }
        .word-title { font-size: 1.15rem; font-weight: 800; }
        .word-snippet { font-size: 0.8rem; color: var(--text-secondary); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
        .mastery-progress-bar { display: flex; gap: 4px; margin-top: 4px; }
        .progress-dot { width: 14px; height: 4px; border-radius: 2px; background: var(--border-color); }
        .progress-dot.filled { background: var(--accent-primary); }

        .family-modal { width: 95%; max-width: 420px; background: var(--card-bg); border-radius: 28px; overflow: hidden; animation: familyUp 0.3s ease-out; }
        @keyframes familyUp { from { transform: translateY(40px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
        .family-modal .modal-header { padding: 1.25rem 1.5rem; border-bottom: 1px solid var(--border-color); display: flex; justify-content: space-between; align-items: center; }
        .family-modal .modal-scroll-area { padding: 1.25rem; max-height: 60vh; overflow-y: auto; }
        .member-row { padding: 1rem; border-radius: 16px; background: var(--bg-color); border: 1px solid var(--border-color); display: flex; align-items: center; margin-bottom: 8px; cursor: pointer; }
        .member-row.is-saved { border-color: var(--accent-primary); background: var(--card-bg); }
        .member-name { font-weight: 800; font-size: 1rem; }
        .member-pos { font-size: 0.7rem; color: var(--accent-primary); margin-left: 4px; }
        .member-def { font-size: 0.75rem; color: var(--text-secondary); margin-top: 4px; }
        .member-saved-badge { font-size: 0.6rem; font-weight: 900; background: var(--accent-primary); color: white; padding: 2px 6px; border-radius: 4px; margin-left: 8px; }
      `}</style>
    </div>
  );
};

